import type { TradeSlot } from './TradeUpdateParser';

type TradeState = {
isOpen: boolean;
sessionId: number;
userAId: number;
userBId: number;
usernameA: string;
usernameB: string;
slots: number;

aConfirmed: boolean;
bConfirmed: boolean;
aSlots: TradeSlot[];
bSlots: TradeSlot[];

lastResult?: { success: boolean; message: string };
};

type Listener = (state: TradeState) => void;

const defaultState: TradeState = {
isOpen: false,
sessionId: 0,
userAId: 0,
userBId: 0,
usernameA: '',
usernameB: '',
slots: 6,

aConfirmed: false,
bConfirmed: false,
aSlots: Array.from({ length: 6 }, () => ({ hasItem: false })),
bSlots: Array.from({ length: 6 }, () => ({ hasItem: false }))
};

export class TradeStore
{
private static _state: TradeState = { ...defaultState };
private static _listeners: Set<Listener> = new Set();

public static getState(): TradeState
{
return this._state;
}

public static onUpdate(fn: Listener): () => void
{
this._listeners.add(fn);
return () => this._listeners.delete(fn);
}

public static clearListeners(): void
{
this._listeners.clear();
}

private static emit(): void
{
for(const fn of this._listeners) fn(this._state);
}

public static open(payload: Partial<TradeState>): void
{
this._state = {
...this._state,
...payload,
isOpen: true
};

// Ensure slot arrays exist in correct length
const n = this._state.slots || 6;
if(!this._state.aSlots || this._state.aSlots.length !== n) this._state.aSlots = Array.from({ length: n }, () => ({ hasItem: false }));
if(!this._state.bSlots || this._state.bSlots.length !== n) this._state.bSlots = Array.from({ length: n }, () => ({ hasItem: false }));

this.emit();
}

public static update(payload: Partial<TradeState>): void
{
this._state = { ...this._state, ...payload };
this.emit();
}

public static result(success: boolean, message: string): void
{
this._state = { ...this._state, lastResult: { success, message } };
this.emit();
}

public static close(): void
{
this._state = { ...defaultState };
this.emit();
}
}
